/* Test driver */
public class Main {
    public static void main(String[] args) {
        DatabaseConnection.resetCounter();
        PoolConfig cfg = new PoolConfig(1, 3, 60000);
        ObjectPool<DatabaseConnection> pool = new ObjectPool<>(new DatabaseConnectionFactory(), new ConnectionValidator(), cfg);
        DatabaseConnection c1 = pool.borrow();
        String id1 = c1.getId();
        pool.returnObject(c1);
        DatabaseConnection c2 = pool.borrow();
        System.out.println("REUSE=" + id1.equals(c2.getId()) + " ACTIVE=" + pool.getActiveCount());
    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) {
        DatabaseConnection.resetCounter();
        PoolConfig cfg = new PoolConfig(0, 2, 60000);
        ObjectPool<DatabaseConnection> pool = new ObjectPool<>(new DatabaseConnectionFactory(), new ConnectionValidator(), cfg);
        pool.borrow();
        pool.borrow();
        try { pool.borrow(); System.out.println("WRONG"); } catch (RuntimeException e) { System.out.println("EXHAUSTED:" + e.getMessage()); }
    }
}
